// --- handleLifecycleSessionEnd tests ---

func TestHandleLifecycleSessionEnd_EmptySessionID(t *testing.T) {
	t.Parallel()

	ag := newMockAgent()
	event := &agent.Event{
		Type:      agent.SessionEnd,
		SessionID: "", // Empty
	}

	// Empty session ID should return nil (no error, just no-op)
	err := handleLifecycleSessionEnd(ag, event)
	if err != nil {
		t.Errorf("expected no error for empty session ID on SessionEnd, got: %v", err)

	// Create state file
	stateFile := prePromptStateFile(sessionID)
	state := PrePromptState{
		SessionID:        sessionID,
		Timestamp:        time.Now().UTC().Format(time.RFC3339),
		UntrackedFiles:   untrackedFiles,
		TranscriptOffset: transcriptOffset,
	}

	data, err := jsonutil.MarshalIndentWithNewline(state, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal state: %w", err)
	}

	if err := os.WriteFile(stateFile, data, 0o600); err != nil {
		return fmt.Errorf("failed to write state file: %w", err)
	}

	fmt.Fprintf(os.Stderr, "Captured state before prompt: %d untracked files, transcript offset: %d\n",
		len(untrackedFiles), transcriptOffset)
	return nil
}

